#include <bits/stdc++.h>
using namespace std;

#define ll long long
#define rep(i, n) for(int i = 0; i < (int)(n); i++)
#define all(x) (x).begin(), (x).end()

const int INF = 1e9;
const int MAX_N = 8;
const int MAX_M = 1e5;

int N, M;
int W[MAX_N];
int L[MAX_M], V[MAX_M];

bool check(int d) {
    vector<int> l(M + 1);
    rep(i, M) {
        l[i + 1] = l[i] + d;
    }
    rep(i, M + 1) {
        ll sum = 0;
        rep(j, N) {
            if (l[i] - l[i - 1] <= W[j]) {
                sum += W[j];
            }
        }
        if (sum > V[i]) {
            return false;
        }
    }
    return true;
}

int main() {
    cin >> N >> M;
    rep(i, N) {
        cin >> W[i];
    }
    rep(i, M) {
        cin >> L[i] >> V[i];
    }
